#!/usr/bin/env python3
"""
GWAS Enrichment Analysis: Schizophrenia-Associated Genes vs Brain Cell Type Markers

This script performs enrichment analysis to test whether schizophrenia-associated
genes from GWAS Catalog are enriched for specific brain cell type markers.

WHY: We want to determine which cell types are most affected in schizophrenia by
testing if known SCZ risk genes overlap with cell-type-specific marker genes more
than expected by chance.

Method: Fisher's exact test (hypergeometric distribution) with FDR correction
across multiple cell type comparisons.

API: EBI GWAS Catalog REST API v1
"""

import json
import time
import sys
from pathlib import Path
from typing import Dict, List, Tuple, Optional, Any
from datetime import datetime

import requests
import numpy as np
from scipy import stats
from statsmodels.stats.multitest import multipletests

