SCRIPT_DIR = Path(__file__).parent
OUTPUT_DIR = SCRIPT_DIR
RESULTS_FILE = OUTPUT_DIR / "results.json"
CHALLENGE_FILE = OUTPUT_DIR / "challenge.md"
LOG_FILE = OUTPUT_DIR / "gwas_enrichment.log"

# EBI GWAS Catalog API endpoints
GWAS_API_BASE = "https://www.ebi.ac.uk/gwas/api/rest/v1"
MAX_RETRIES = 3
RETRY_DELAY = 2  # seconds

