    for r in results:
        if r["status"] == "TESTED":
            challenge_md += f"| {r['cell_type']} | {r['n_markers']} | {r['overlap']} | "
            challenge_md += f"{r['odds_ratio']:.2f} | {r['fdr_corrected_p']:.4f} | "
            challenge_md += f"{r.get('pattern', 'N/A')} |\n"
        else:
            challenge_md += f"| {r['cell_type']} | {r['n_markers']} | "
            challenge_md += f"UNINTERPRETABLE | - | - | {r.get('pattern', 'UNINTERPRETABLE')} |\n"

    with open(CHALLENGE_FILE, "w") as f:
        f.write(challenge_md)
    log(f"Challenge report written to {CHALLENGE_FILE}")

    log("\n" + "=" * 80)
    log("ANALYSIS COMPLETE")
